THOUGHT: The segfault shows ScalarEvolution::LoopGuards repeatedly recursing through PHI/blocks, likely causing pathological growth or cycles during guard collection. In collectFromPHI, VisitedBlocks is globally mutated per incoming edge, which can both block future edges and fail to prevent cycles across recursive calls. To stabilize recursion and avoid infinite revisits, I will:
- Add an early depth guard in collectFromPHI to honor MaxLoopGuardCollectionDepth.
- Use a local copy of VisitedBlocks when recursing via collectFromBlock from PHI, so each incoming path has its own visitation set, preventing cross-edge pollution and better cycle handling.
These changes should break the infinite recursion leading to the crash.

```bash
applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Analysis/ScalarEvolution.cpp
@@
 void ScalarEvolution::LoopGuards::collectFromPHI(
     ScalarEvolution &SE, ScalarEvolution::LoopGuards &Guards,
     const PHINode &Phi, SmallPtrSetImpl<const BasicBlock *> &VisitedBlocks,
     SmallDenseMap<const BasicBlock *, LoopGuards> &IncomingGuards,
     unsigned Depth) {
+  // Respect recursion depth limit when collecting guards through PHIs to avoid
+  // pathological recursion on self-referential headers/blocks.
+  if (Depth >= MaxLoopGuardCollectionDepth)
+    return;
   if (!SE.isSCEVable(Phi.getType()))
     return;

   using MinMaxPattern = std::pair<const SCEVConstant *, SCEVTypes>;
   auto GetMinMaxConst = [&](unsigned IncomingIdx) -> MinMaxPattern {
     const BasicBlock *InBlock = Phi.getIncomingBlock(IncomingIdx);
-    if (!VisitedBlocks.insert(InBlock).second)
-      return {nullptr, scCouldNotCompute};
+    // Use a local visited set for the recursive traversal starting from this
+    // incoming edge to prevent cross-edge pollution and better handle cycles.
+    SmallPtrSet<const BasicBlock *, 8> LocalVisitedBlocks(VisitedBlocks.begin(),
+                                                          VisitedBlocks.end());
+    if (!LocalVisitedBlocks.insert(InBlock).second)
+      return {nullptr, scCouldNotCompute};
     auto [G, Inserted] = IncomingGuards.try_emplace(InBlock, LoopGuards(SE));
     if (Inserted)
-      collectFromBlock(SE, G->second, Phi.getParent(), InBlock, VisitedBlocks,
+      collectFromBlock(SE, G->second, Phi.getParent(), InBlock, LocalVisitedBlocks,
                        Depth + 1);
     auto &RewriteMap = G->second.RewriteMap;
     if (RewriteMap.empty())
       return {nullptr, scCouldNotCompute};
*** End Patch
PATCH
```

